from fastapi import FastAPI

app = FastAPI()
users_db = {1: {"id": 1, "name": "Alice", "email": "alice@example.com"}}

@app.get("/users/{user_id}")
def get_user(user_id: int):  # READ
    return users_db.get(user_id, {"error": "Not found"})

@app.post("/users")
def create_user(user: dict):  # CREATE
    new_id = max(users_db.keys()) + 1
    user["id"] = new_id
    users_db[new_id] = user
    return user

@app.put("/users/{user_id}")
def update_user(user_id: int, user: dict):  # REPLACE
    user["id"] = user_id
    users_db[user_id] = user
    return user

@app.delete("/users/{user_id}")
def delete_user(user_id: int):  # DELETE
    return users_db.pop(user_id, {"error": "Not found"})
